INSERT INTO content (title, type, content, summary, tags, priority, status, view_count, publish_time, create_time) VALUES
('春季门诊就医准备清单', 'article', '# 春季门诊就医准备清单\n\n- 提前预约挂号\n- 带好医保卡/身份证\n- 近 3 个月检查报告整理好\n\n> 建议提前 20 分钟到院，避免高峰拥堵。', '就医前准备材料、时间安排与到院建议，减少现场等待。', '就医指南,门诊,准备清单', 0, 'published', 56, '2025-02-11 09:30:00', '2025-02-10 16:20:00'),
('高血压复诊沟通要点', 'article', '# 高血压复诊沟通要点\n\n1. 近两周家庭血压记录\n2. 服药时间与不适反应\n3. 饮食与运动执行情况\n\n**重点**：不要凭感觉停药。', '围绕血压记录、用药反应和生活方式，帮助患者高效复诊沟通。', '慢病管理,高血压,复诊', 0, 'published', 32, '2025-02-15 10:00:00', '2025-02-14 18:10:00'),
('节假日门诊服务时间调整通知', 'announcement', '# 节假日门诊服务时间调整\n\n部分门诊在节假日实行半日门诊，请提前确认排班。\n\n- 线上问诊通道正常开放\n- 急诊 24 小时不受影响', '请提前查看各院区节假日排班，避免空跑。', 'targets:users,companions', 10, 'published', 120, '2025-02-16 12:00:00', '2025-02-16 11:30:00'),
('陪诊服务规范升级公告', 'announcement', '# 陪诊服务规范升级\n\n平台将于下周上线新的服务留痕要求，保障患者权益与服务质量。', '下周起执行新服务留痕规范，陪诊员请提前查看规则。', 'targets:companions', 8, 'published', 88, '2025-02-18 08:00:00', '2025-02-17 19:20:00');
